PyTypeObject* DoInitWrapperScrollBox(const UClass* InClass, PyTypeObject* InSuperType, PyObject* InSuperTypes)
{
	if (InClass == nullptr)
	{
		return nullptr;
	}

	if (FUPyWrapperTypeRegistry::Get().HasWrappedClassType(InClass))
	{
		return const_cast<PyTypeObject*>(FUPyWrapperTypeRegistry::Get().GetWrappedClassType(InClass));
	}

	PyTypeObject* PyType = &UPyWrapperScrollBoxType;
	PyType->tp_flags = Py_TPFLAGS_DEFAULT | Py_TPFLAGS_BASETYPE;
	PyType->tp_base = InSuperType != nullptr ? InSuperType : &UPyWrapperObjectType;
	PyType->tp_bases = InSuperTypes;
	PyType->tp_methods = FUPyWrapperScrollBoxPyMethodDefs;
	PyType->tp_getset = FUPyWrapperScrollBoxGetSets;

	if (PyType_Ready(PyType) == 0)
	{
		FUPyWrapperTypeRegistry::Get().RegisterWrappedClassType(InClass, PyType);
		return PyType;
	}

	return nullptr;
}

void InitializeUPyWrapperScrollBox(UPyGenUtil::FNativePythonModule& ModuleInfo)
{
	FUPyWrapperTypeRegistry::Get().RegisterAutoWrappedClassCreateFunc(UScrollBox::StaticClass(), DoInitWrapperScrollBox);
}

FUPyWrapperScrollBox* UPyIsScrollBox(PyObject* InSelf)
{
	if (InSelf && PyObject_IsInstance(InSelf, (PyObject*)&UPyWrapperScrollBoxType))
	{
		return (FUPyWrapperScrollBox*)InSelf;
	}
	return nullptr;
}

namespace UPyConversion
{
	FUPyConversionResult Nativize(PyObject* PyObj, UScrollBox*& OutVal, const ESetErrorState SetErrorState)
	{
		if (FUPyWrapperScrollBox* PyScrollBox = UPyIsScrollBox(PyObj))
		{
			if (!FUPyWrapperObject::ValidateInternalState(PyScrollBox))
			{
				return FUPyConversionResult::Failure();
			}

			OutVal = PyScrollBox->ValuePtr();
			return FUPyConversionResult::Success();
		}

		UPYCONVERSION_RETURN(FUPyConversionResult::Failure(), TEXT("Nativize"), *FString::Printf(TEXT("Cannot nativize '%s' as 'UScrollBox'"), *UPyUtil::GetFriendlyTypename(PyObj)));
	}
}
